#!/usr/bin/env bun
/**
 * Captures git provenance at build time and writes src/build-info.ts.
 *
 * Bun's bundler embeds this generated file into the compiled binary, so the
 * resulting binary "remembers" which repo/branch/commit it was built from.
 * That's the point: when someone runs --version on a fork-built binary, the
 * output should make the fork obvious.
 *
 * Runs in three contexts with different expectations:
 *   - Local dev / CI build   — git available, full info captured
 *   - npm publish (prepublishOnly) — git available in the publisher's checkout
 *   - End-user `npm install` (prepare) — usually no git; falls back to empty
 *
 * On any failure (git missing, not a repo, command errors), we write an
 * empty BUILD_INFO and let formatVersion() degrade gracefully to just the
 * version line. We never crash the install.
 *
 * Run: bun scripts/generate-build-info.ts
 */

import { writeFileSync } from "node:fs";
import { execSync } from "node:child_process";
import { join } from "node:path";

const PROJECT_ROOT = join(import.meta.dir, "..");
const OUTPUT_FILE = join(PROJECT_ROOT, "src", "build-info.ts");

interface BuildInfo {
  repo: string | null;
  branch: string | null;
  commit: string | null;
  dirty: boolean;
}

function tryGit(args: string): string | null {
  try {
    const out = execSync(`git ${args}`, {
      cwd: PROJECT_ROOT,
      encoding: "utf8",
      stdio: ["ignore", "pipe", "ignore"],
    });
    return out.trim() || null;
  } catch {
    return null;
  }
}

/**
 * Canonicalize a git remote URL into a single comparable form. Different
 * sources produce different shapes for the same repo:
 *   - local clone via ssh:        git@github.com:owner/repo.git
 *   - local clone via https+git:  https://github.com/owner/repo.git
 *   - actions/checkout in CI:     https://github.com/owner/repo
 * All three normalize to `https://github.com/owner/repo` so `--version` output
 * is identical across build environments and the upstream-repo equality check
 * in update.ts works regardless of where the binary was built.
 */
function normalizeRepoUrl(url: string | null): string | null {
  if (!url) return null;
  let normalized = url;
  // ssh form: git@host:owner/repo[.git]
  const sshMatch = normalized.match(/^git@([^:]+):(.+?)(?:\.git)?$/);
  if (sshMatch) {
    const [, host, path] = sshMatch;
    normalized = `https://${host}/${path}`;
  }
  // git:// form
  if (normalized.startsWith("git://")) {
    normalized = "https://" + normalized.slice("git://".length);
  }
  // Strip `.git` suffix and any trailing slashes
  normalized = normalized.replace(/\.git$/, "").replace(/\/+$/, "");
  return normalized;
}

function captureBuildInfo(): BuildInfo {
  const repoRaw = tryGit("remote get-url origin");
  const repo = normalizeRepoUrl(repoRaw);
  const branchRaw = tryGit("rev-parse --abbrev-ref HEAD");
  // Detached HEAD shows up as "HEAD" — treat as no branch
  const branch = branchRaw === "HEAD" ? null : branchRaw;
  const commit = tryGit("rev-parse --short HEAD");
  // `git status --porcelain` outputs nothing on a clean tree, lines on dirty
  const status = tryGit("status --porcelain");
  const dirty = status !== null && status.length > 0;

  return { repo, branch, commit, dirty };
}

function generate(): void {
  const info = captureBuildInfo();

  const output = `// Auto-generated by scripts/generate-build-info.ts — DO NOT EDIT
// Regenerate: bun scripts/generate-build-info.ts
// Captures git provenance at build time so --version can show fork/branch/commit.

export interface BuildInfo {
  repo: string | null;
  branch: string | null;
  commit: string | null;
  dirty: boolean;
}

export const BUILD_INFO: BuildInfo = ${JSON.stringify(info, null, 2)};
`;

  writeFileSync(OUTPUT_FILE, output, "utf8");

  const summary = info.repo || info.branch || info.commit
    ? `repo=${info.repo ?? "?"} branch=${info.branch ?? "?"} commit=${info.commit ?? "?"}${info.dirty ? " (dirty)" : ""}`
    : "no git context (release build)";
  process.stdout.write(`Generated ${OUTPUT_FILE}: ${summary}\n`);
}

generate();
